module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const min = parseFloat(args.min); const max = parseFloat(args.max);
const step = Math.abs(parseFloat(args.step)) || 1;
const color = args.color || 'var(--accent-color)';
const showTicks = String(args.ticks) !== 'false';
const unit = args.unit ? String(args.unit) : '';
const arrow = String(args.arrow) !== 'false';
const dp = parseFloat(args.dotSize);
const dot = Number.isFinite(dp) ? Math.max(6, Math.min(24, dp)) : 12;
const lo = Number.isFinite(min) ? min : 0, hi = Number.isFinite(max) ? max : 10;
const span = (hi - lo) || 1;
const pct = (v) => ((v - lo) / span) * 100;
let ticks = '';
for (let v = Math.ceil(lo / step) * step; v <= hi + 1e-9; v += step) {
  const lab = showTicks ? `<span>${(+v.toFixed(6))}${esc(unit)}</span>` : '';
  ticks += `<div class="mdp-nl-tick" style="left:${pct(v).toFixed(2)}%;">${lab}</div>`;
}
let marks = '';
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const iv = s.match(/^([\[(])\s*(-?[\d.]+)\s*,\s*(-?[\d.]+)\s*([\])])\s*([\s\S]*)$/);
  if (iv) {
    const a = parseFloat(iv[2]), b = parseFloat(iv[3]);
    const x1 = Math.max(0, Math.min(100, pct(Math.min(a, b)))), x2 = Math.max(0, Math.min(100, pct(Math.max(a, b))));
    marks += `<div class="mdp-nl-interval" style="left:${x1.toFixed(2)}%; width:${(x2 - x1).toFixed(2)}%; --nl-c:${color};">` +
      `<span class="mdp-nl-end ${iv[1] === '[' ? 'closed' : 'open'}"></span><span class="mdp-nl-end r ${iv[4] === ']' ? 'closed' : 'open'}"></span></div>` +
      (iv[5].trim() ? `<div class="mdp-nl-lbl" style="left:${((x1 + x2) / 2).toFixed(2)}%;">${esc(iv[5].trim())}</div>` : '');
    return;
  }
  const pt = s.match(/^(-?[\d.]+)\s*([\s\S]*)$/);
  if (pt) {
    const x = pct(parseFloat(pt[1]));
    marks += `<div class="mdp-nl-point" style="left:${x.toFixed(2)}%; --nl-c:${color};"></div>` +
      (pt[2].trim() ? `<div class="mdp-nl-lbl" style="left:${x.toFixed(2)}%;">${esc(pt[2].trim())}</div>` : '');
  }
});
const lineCls = 'mdp-nl-line' + (arrow ? '' : ' mdp-nl-noarrow');
return `\n\n<div class="mdp-mod-numberline" style="--nl-dot:${dot}px;"><div class="${lineCls}">${ticks}${marks}</div></div>\n\n`;
